channels = get_channels()
matching_channels = [channel for channel in channels if channel.lower().startswith("external")]

if len(matching_channels) == 0:
    raise ValueError("No channel starts with 'External'.")
if len(matching_channels) > 1:
    raise NotEnoughInformationError("Multiple channels start with 'External': {}".format(repr(matching_channels)))

target_channel = matching_channels[0]

users_by_channel = [get_users_in_channel(channel) for channel in channels]
all_users = sorted(set([user for channel_users in users_by_channel for user in channel_users]))

exact_matches = [user for user in all_users if user == "Charlie"]
case_insensitive_exact_matches = [user for user in all_users if user.lower() == "charlie"]
prefix_matches = [user for user in all_users if user.lower().startswith("charlie")]

if len(exact_matches) == 1:
    target_user = exact_matches[0]
elif len(case_insensitive_exact_matches) == 1:
    target_user = case_insensitive_exact_matches[0]
elif len(prefix_matches) == 1:
    target_user = prefix_matches[0]
elif len(prefix_matches) > 1:
    raise NotEnoughInformationError("Multiple users match 'Charlie': {}".format(repr(prefix_matches)))
else:
    target_user = "Charlie"

channel_users = get_users_in_channel(target_channel)

if target_user in channel_users:
    print("{} is already in {}.".format(target_user, target_channel))
else:
    add_user_to_channel(target_user, target_channel)
    print("Added {} to {}.".format(target_user, target_channel))
